def solution(n: int = 100):
    ways = [0] * (n + 1)
    ways[0] = 1
    # Iterate through each number we can use in the sum (1 up to n-1)
    for i in range(1, n):
        for j in range(i, n + 1):
            ways[j] += ways[j - i]
    return ways[n]


if __name__ == "__main__":
    print(solution(100))
